mapper.select:
select id, user_id, scooter_id, start_time, end_time, total_time, order_status, pay_status, amount, total_kilometer, create_time
from rental_order
where id = #{id}

select ifnull(sum(total_time), 0)
from rental_order
where user_id = #{userId}

select ifnull(sum(total_kilometer), 0)
from rental_order
where user_id = #{userId}
